Using Microsoft.Dynamics365.LocalizationFramework;
/// <summary>
/// The service class of Shipping instructions ER report
/// </summary>
internal final class ETG_ShippingInstructionsERService extends SysOperationServiceBase
{
    public const str ERModelDataSourceName = 'model';
    public const str ParametersDataSourceName = 'RunTimeParameters';

}

Method.Source:
/// <summary>
/// Generates report by using Electronic reporting framework
/// </summary>
/// <param name = "_contract">The Shipping instructions contract </param>
public static void generateReportByGER(AgreementConfirmationRDPContract _contract)
{
    ERFormatMappingId formatMappingId;
    ERFormatMappingTable erFormatMappingTable;
    Description reportName;

    reportName = "ETG Shipping Instructions(Word)";

    select firstonly RecId from erFormatMappingTable
    where erFormatMappingTable.Name == reportName;

    formatMappingId = erFormatMappingTable.RecId;

    if (formatMappingId)
    {
        try
        {
            ERIModelDefinitionParamsAction parameters = new ERModelDefinitionParamsUIActionComposite()
            .add(new ERModelDefinitionObjectParameterAction(ERModelDataSourceName, ParametersDataSourceName, _contract, true));

            // Call ER to generate the report.
            ERIFormatMappingRun formatMappingRun = ERObjectsFactory::createFormatMappingRunByFormatMappingId(formatMappingId);
            formatMappingRun.withParameter(parameters);
            formatMappingRun.run();
        }
        catch
        {
            // An error occurred while exporting data.
            error("@SYP4861341");
        }
    }
    else
    {
        // There is no data available.
        info("@SYS300117");
    }
}
